#!/bin/bash
# Deploy AI Visibility v4: auto-detect business location + editable field
# Upload this to Cloud Shell and run: bash deploy_v4_upload.sh
set -e
cd ~/chaos_tester

echo "=== AI Visibility v4: Auto-detect + Editable Location ==="

# 1. Patch app.py using Python (adds business_location + detect endpoint)
echo "Step 1: Patching app.py..."
base64 -d > /tmp/patch_app.py << 'B64_PATCH'

B64_PATCH
python3 /tmp/patch_app.py

# 2. Patch config.py (add business_location field)
echo "Step 2: Patching config.py..."
if ! grep -q "business_location" config.py; then
  sed -i '/run_ai_visibility: bool = True/a\    business_location: str = ""           # optional user-provided city for AI queries' config.py
  echo "  Added business_location field to config"
else
  echo "  business_location already in config"
fi
python3 -c "import ast; ast.parse(open('config.py').read()); print('config.py: VALID')"

# 3. Write updated dashboard.html (with auto-detect UI + JS)
echo "Step 3: Writing templates/dashboard.html..."
base64 -d > templates/dashboard.html << 'B64_DASH'

B64_DASH
echo "  dashboard.html: $(wc -l < templates/dashboard.html) lines"

# 4. Git commit & deploy
echo ""
echo "Step 4: Committing and deploying..."
git add app.py config.py templates/dashboard.html
git commit -m "feat: auto-detect business location with editable field

- Added /api/detect-business POST endpoint for quick business info lookup
- Dashboard auto-detects business name, sector, location when URL is entered
- Location field pre-populated with detected city (user can edit)
- Shows detected business name, sector, and location source
- Added business_location to ChaosConfig for form submission
"
git push origin main

echo ""
echo "Deploying to Cloud Run..."
gcloud run deploy chaos-tester --source . --region us-central1 --allow-unauthenticated --project chaos-tester

echo ""
echo "=== Deploy complete! ==="
echo "Test: https://website-auditor.io"
